import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it.todo("should return an empty array when given an empty input (no live cells)");

  it.todo("should kill a single isolated live cell — [(0,0)] becomes []");

  it.todo("should kill two adjacent live cells with only 1 neighbor each (Rule 1 Underpopulation) — [(0,1), (1,1)] becomes []");

  it.todo("should bring a dead cell with exactly 3 live neighbors to life (Rule 4 Reproduction) — L-shape [(0,2), (1,2), (0,1)] produces square including (1,1)");

  it.todo("should keep a live cell alive when it has 3 live neighbors (Rule 2 Survival) — top row ### plus (1,-1) → center (1,1) survives");

  it.todo("should kill a live cell with 4 live neighbors (Rule 3 Overpopulation) — full 3x3 minus middle row sides: center (1,1) dies");

  it.todo("should keep a 2x2 block unchanged across generations (Block still life) — [(0,0), (1,0), (0,1), (1,1)] stays the same");

  it.todo("should oscillate a vertical blinker to a horizontal blinker — [(0,0), (0,1), (0,2)] becomes [(-1,1), (0,1), (1,1)]");

  it.todo("should handle negative coordinates correctly — blinker at negative origin oscillates as expected");
});
